'use strict';

const { allProducts } = require('../core/products.js');

function listProducts() {
  return allProducts().map((p) => `${p.id}  ${p.name}  $${p.price.toFixed(2)}`);
}

module.exports = { listProducts };
```

**Key characteristics**:
- Single function exported with command-named export (`listProducts`)
- Returns an array of strings (one per output line) or null/undefined (no output)
- No arguments (rest parameter is empty)
- Dependencies imported from `src/core/` modules

#### Pattern B: Command with Arguments & Error Handling (add-product.js)
```javascript
'use strict';

const { AppError } = require('../lib/errors.js');

// In-session product additions (not persisted across runs).
const added = [];

function addProduct(args) {
  const [id, name, priceStr] = args;
  if (!id || !name || !priceStr) {
    throw new AppError('usage: add-product <id> <name> <price>', 2);
  }
  const price = parseFloat(priceStr);
  if (isNaN(price)) {
    throw new AppError('price must be a number', 2);
  }
  added.push({ id, name, price });
  return [`added product ${id}`];
}

module.exports = { addProduct };
```

**Key characteristics**:
- Receives `args` array (from command line after command name)
- Destructures arguments directly
- Throws `AppError` with exit code 2 for usage/validation errors
- Returns feedback array with confirmation message
- Can maintain module-level state (added array)

#### Pattern C: Metadata Command with Dynamic Registry Access (help.js)
```javascript
