// Lazy-requires registry to avoid circular dependency at module load time.
function help() {
  const { COMMANDS } = require('./registry.js');
  const names = Object.keys(COMMANDS).sort();
  return ['available commands:', ...names.map((n) => `  ${n}`)];
}

module.exports = { help };
```

**Key characteristics**:
- Lazy requires inside function to avoid circular dependencies at module load
- Accesses registry dynamically
- Formats output as array of lines

