  const cleanArgs = [];

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--format' && i + 1 < args.length) {
      format = args[i + 1];
      i++; // skip the value
    } else {
      cleanArgs.push(args[i]);
    }
  }

  if (!['csv', 'json'].includes(format)) {
